        EmojiEntry(shortcode: "zzz", emoji: "\u{1F4A4}", aliases: ["sleeping"]),
    ]

    public static func search(query: String, limit: Int = 8) -> [EmojiEntry] {
        let lowered = query.lowercased()
        if lowered.isEmpty {
            return Array(all.prefix(limit))
        }
        var shortcodePrefix: [EmojiEntry] = []
        var shortcodeSubstring: [EmojiEntry] = []
        var aliasPrefix: [EmojiEntry] = []
        var aliasSubstring: [EmojiEntry] = []
        var seen = Set<String>()
        for entry in all {
            if entry.shortcode.hasPrefix(lowered) {
                shortcodePrefix.append(entry)
                seen.insert(entry.shortcode)
            } else if entry.shortcode.contains(lowered) {
                shortcodeSubstring.append(entry)
                seen.insert(entry.shortcode)
            }
        }
        for entry in all where !seen.contains(entry.shortcode) {
            var sawPrefix = false
            var sawSubstring = false
            for alias in entry.aliases {
                if alias.hasPrefix(lowered) {
                    sawPrefix = true
                    break
                }
                if alias.contains(lowered) {
                    sawSubstring = true
                }
            }
            if sawPrefix {
                aliasPrefix.append(entry)
            } else if sawSubstring {
                aliasSubstring.append(entry)
            }
        }
        return Array((shortcodePrefix + shortcodeSubstring + aliasPrefix + aliasSubstring).prefix(limit))
    }
}
